/**
 * Настройки топика.
 * Используются при создании экземпляра для управления локальным кешем, частотой синхронизации
 * и значением, которое может быть записано на сервер при первом подключении.
 */
export interface TopicOptions {
    /**
     * Значение по умолчанию для топика.
     * Записывается при первом подключении сервиса, если топик на сервере еще не создан.
     */
    defaultValue?: any;
    /**
     * Частота чтения локального кеша в миллисекундах.
     * Меньшее значение увеличивает частоту обращений и нагрузку.
     */
    readCacheFrequency?: number;
    /**
     * Частота записи локального кеша в миллисекундах.
     * Отправляет на сервер только измененные значения и снижает сетевой трафик.
     */
    writeCacheFrequency?: number;
}

/**
 * Клиентский объект топика.
 * Управляет локальным кешем, синхронизацией значений с платформой и обеспечивает доступ
 * к данным топика для сервиса.
 */
declare class RemoteTopic {
    /**
     * Создает и регистрирует топик.
     * Настраивает локальный кеш и запускает фоновую синхронизацию значений с сервером.
     * @param path Путь топика.
     * @param options Настройки кеша и значения по умолчанию.
     */
    constructor(path: string, options?: TopicOptions);

    /**
     * Локально закешированное значение топика.
     * Возвращается без обращения к серверу и может отличаться от актуального значения.
     */
    get value(): any;
    /**
     * Обновляет локальный кеш топика.
     * Запись на сервер выполняется в соответствии с настройками синхронизации.
     * @param value Новое значение для локального кеша.
     */
    set value(value: any);

    /**
     * Регистрирует обработчик изменения значения топика.
     * Срабатывает при обновлении локального кеша новым значением.
     * @param handler Обработчик изменения значения.
     */
    onChange(handler: (value: any) => void): void;

    /**
     * Удаляет обработчик изменения значения топика.
     * @param handler Обработчик изменения значения.
     */
    offChange(handler: (value: any) => void): void;

    /**
     * Ожидает первое получение значения топика с платформы.
     * Разрешается после получения первого значения, включая undefined.
     */
    waitSync(): Promise<void>;

    /**
     * Инициализирует соединение сервиса с платформой.
     * Включает обмен данными и регистрацию топиков для дальнейшей работы экземпляров.
     * @param serviceName Имя сервиса.
     * @param url Адрес платформы.
     */
    static initialize(serviceName: string, url: string): void;

    /**
     * Айди запуска платформы, полученный при подключении сервиса.
     * Может быть undefined до завершения регистрации.
     */
    static get platformRunId(): number | undefined;

    /**
     * Состояние подключения сервиса к платформе.
     * true если соединение активно, иначе false.
     */
    static get isConnected(): boolean;

    /**
     * Регистрирует обработчик события подключения к платформе.
     * Если соединение уже активно, обработчик будет вызван сразу.
     * @param handler Обработчик события подключения.
     */
    static onConnected(handler: () => void): void;

    /**
     * Удаляет обработчик события подключения к платформе.
     * @param handler Обработчик события подключения.
     */
    static offConnected(handler: () => void): void;

    /**
     * Регистрирует обработчик события отключения от платформы.
     * Если соединение не активно, обработчик будет вызван сразу.
     * @param handler Обработчик события отключения.
     */
    static onDisconnected(handler: () => void): void;

    /**
     * Удаляет обработчик события отключения от платформы.
     * @param handler Обработчик события отключения.
     */
    static offDisconnected(handler: () => void): void;

    /**
     * Возвращает список топиков из указанного каталога.
     * Базовый путь задается так же, как и при создании топиков.
     * @param folderPath Базовый путь каталога.
     * @param options Дополнительные параметры запроса.
     */
    static listTopicsFromFolder(
        folderPath: string,
        options?: {
            /**
             * Включает рекурсивный поиск по подкаталогам.
             */
            recursive?: boolean;
            /**
             * Возвращает абсолютные пути топиков.
             */
            absolutePath?: boolean;
        }
    ): Promise<string[]>;

    /**
     * Устанавливает флаг сохранения для указанного топика.
     * @param topicName Путь топика.
     * @param safe Новый флаг сохранения.
     */
    static setTopicSafe(topicName: string, safe: boolean): Promise<boolean>;
}

export default RemoteTopic;
